type AutoScalingInitParameters struct {

	// Flag that indicates whether instance size auto-scaling is enabled. This parameter defaults to false. If a sharded cluster is making use of the New Sharding Configuration, auto-scaling of the instance size will be independent for each individual shard. Please reference the Use Auto-Scaling Per Shard section for more details.
	// Flag that indicates whether someone enabled instance size auto-scaling.
	//
	// - Set to `true` to enable instance size auto-scaling. If enabled, you must specify a value for **replicationSpecs[n].regionConfigs[m].autoScaling.compute.maxInstanceSize**.
	// - Set to `false` to disable instance size automatic scaling.
	ComputeEnabled *bool `json:"computeEnabled,omitempty" tf:"compute_enabled,omitempty"`

	// Maximum instance size to which your cluster can automatically scale (such as M40). Atlas requires this parameter if replication_specs[#].region_configs[#].auto_scaling.compute_enabled is true.
	// Minimum instance size to which your cluster can automatically scale. MongoDB Cloud requires this parameter if `"replicationSpecs[n].regionConfigs[m].autoScaling.compute.scaleDownEnabled" : true`.
	ComputeMaxInstanceSize *string `json:"computeMaxInstanceSize,omitempty" tf:"compute_max_instance_size,omitempty"`

	// Minimum instance size to which your cluster can automatically scale (such as M10). Atlas requires this parameter if replication_specs[#].region_configs[#].auto_scaling.compute_scale_down_enabled is true.
	// Minimum instance size to which your cluster can automatically scale. MongoDB Cloud requires this parameter if `"replicationSpecs[n].regionConfigs[m].autoScaling.compute.scaleDownEnabled" : true`.
	ComputeMinInstanceSize *string `json:"computeMinInstanceSize,omitempty" tf:"compute_min_instance_size,omitempty"`

	// Flag that indicates whether the instance size may scale down. Atlas requires this parameter if replication_specs[#].region_configs[#].auto_scaling.compute_enabled : true. If you enable this option, specify a value for replication_specs[#].region_configs[#].auto_scaling.compute_min_instance_size.
	// Flag that indicates whether the instance size may scale down. MongoDB Cloud requires this parameter if `"replicationSpecs[n].regionConfigs[m].autoScaling.compute.enabled" : true`. If you enable this option, specify a value for **replicationSpecs[n].regionConfigs[m].autoScaling.compute.minInstanceSize**.
	ComputeScaleDownEnabled *bool `json:"computeScaleDownEnabled,omitempty" tf:"compute_scale_down_enabled,omitempty"`

	// Flag that indicates whether this cluster enables disk auto-scaling. The maximum memory allowed for the selected cluster tier and the oplog size can limit storage auto-scaling. This parameter defaults to false.
	// Flag that indicates whether this cluster enables disk auto-scaling. The maximum memory allowed for the selected cluster tier and the oplog size can limit storage auto-scaling. This parameter defaults to `false`.
	//
	// To set `disk_gb_enabled` to `false`, Atlas requires **advanced_configuration.oplog_min_retention_hours** to be `0` on the server. If it is still non-zero, the API responds with `OPLOG_MIN_RETENTION_HOURS_NO_DISK_AUTO_SCALING` (HTTP 400).
	//
	// Cluster updates are applied before process arguments, so setting **advanced_configuration.oplog_min_retention_hours** to `0` in the same `apply` as disabling disk auto-scaling does not prevent the error.
	//
	// Workaround: Run `apply` twice. First set **advanced_configuration.oplog_min_retention_hours** to `0` and apply. Then set **disk_gb_enabled** to `false` and apply again.
	DiskGbEnabled *bool `json:"diskGbEnabled,omitempty" tf:"disk_gb_enabled,omitempty"`
}

